+    #[test]
+    fn determinism_violation_debug_clone() {
+        init_test("determinism_violation_debug_clone");
+        let v = DeterminismViolation {
+            divergence_index: 5,
+            expected: None,
+            actual: None,
+            context_before: vec![],
+            trace1_len: 10,
+            trace2_len: 8,
+        };
