+    #[test]
+    fn determinism_oracle_identical_traces_ok() {
+        init_test("determinism_oracle_identical_traces_ok");
+        let oracle = DeterminismOracle::new();
+        let trace = vec![TraceEventSummary {
+            seq: 0,
+            time_nanos: 0,
+            kind: TraceEventKind::UserTrace,
